void  init()
{
    FWFTextBlockCopyingHeader   copyingHeader;
    FWFTextBlockCopyingLine     copyingLine;

    next init();

    if (salesPurchCopy == SalesPurchCopy::CopyAllHeader ||
        salesPurchCopy == SalesPurchCopy::CopyAllLines ||
        salesPurchCopy == SalesPurchCopy::CopyJournalHeader ||
        salesPurchCopy == SalesPurchCopy::CopyJournalLines)
    {
        VendFormletterParameters param = VendFormletterParameters::find();

        switch (purchCopyingForm.parmCallerTable().TableId)
        {
            case tableNum(PurchTable):
                copyingHeader = param.FWFTextBlockCopyingHeader;
                copyingLine   = param.FWFTextBlockCopyingLine;
                break;

            case tableNum(PurchRFQCaseTable):
                copyingHeader = param.FWFTextBlockCopyingHeaderRFQCase;
                copyingLine   = param.FWFTextBlockCopyingLineRFQCase;
                break;

            case tableNum(PurchReqTable):
                copyingHeader = param.FWFTextBlockCopyingHeaderReq;
                copyingLine   = param.FWFTextBlockCopyingLineReq;
                break;
        }

        CopyTextblock_Header.value(copyingHeader);
        CopyTextblock_Line.value(copyingLine);
        CopyTextblock_Header.visible(true);
        CopyTextblock_Line.visible(true);
    }
}
